import{_ as e,o as s,c as t,au as r}from"./chunks/framework.Bpqx6pAq.js";const m=JSON.parse('{"title":"Services","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/services.md","filePath":"api/core/services.md"}'),o={name:"api/core/services.md"};function i(n,a,h,l,c,d){return s(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="services" tabindex="-1">Services <a class="header-anchor" href="#services" aria-label="Permalink to &quot;Services&quot;">​</a></h1><h2 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;Users&quot;">​</a></h2><h3 id="users-1" tabindex="-1"><a href="./services/users.html">users</a> <a class="header-anchor" href="#users-1" aria-label="Permalink to &quot;[users](./services/users.md)&quot;">​</a></h3><p>Manages user accounts including profile data, password hashing, password policy enforcement, and ability cache updates. Emits a <code>logout</code> event on removal.</p><h2 id="account" tabindex="-1">Account <a class="header-anchor" href="#account" aria-label="Permalink to &quot;Account&quot;">​</a></h2><h3 id="account-1" tabindex="-1"><a href="./services/account.html">account</a> <a class="header-anchor" href="#account-1" aria-label="Permalink to &quot;[account](./services/account.md)&quot;">​</a></h3><p>Powered by <a href="https://github.com/feathersjs-ecosystem/feathers-authentication-management" target="_blank" rel="noreferrer">feathers-authentication-management</a>. Handles email verification, password reset, and identity change workflows with transactional email notifications.</p><h2 id="authorisations" tabindex="-1">Authorisations <a class="header-anchor" href="#authorisations" aria-label="Permalink to &quot;Authorisations&quot;">​</a></h2><h3 id="authorisations-1" tabindex="-1"><a href="./services/authorisations.html">authorisations</a> <a class="header-anchor" href="#authorisations-1" aria-label="Permalink to &quot;[authorisations](./services/authorisations.md)&quot;">​</a></h3><p>Manages role-based permissions by associating resources with subjects. Uses an LRU cache for computed CASL abilities and patches subject scopes on create/remove.</p><h2 id="mailer" tabindex="-1">Mailer <a class="header-anchor" href="#mailer" aria-label="Permalink to &quot;Mailer&quot;">​</a></h2><h3 id="mailer-1" tabindex="-1"><a href="./services/mailer.html">mailer</a> <a class="header-anchor" href="#mailer-1" aria-label="Permalink to &quot;[mailer](./services/mailer.md)&quot;">​</a></h3><p>Powered by <a href="https://github.com/feathersjs-ecosystem/feathers-mailer" target="_blank" rel="noreferrer">feathers-mailer</a>. Proxies transactional email delivery through an SMTP server. Server-side only.</p><h2 id="push" tabindex="-1">Push <a class="header-anchor" href="#push" aria-label="Permalink to &quot;Push&quot;">​</a></h2><h3 id="push-1" tabindex="-1"><a href="./services/push.html">push</a> <a class="header-anchor" href="#push-1" aria-label="Permalink to &quot;[push](./services/push.md)&quot;">​</a></h3><p>Powered by <a href="https://github.com/kalisio/feathers-webpush" target="_blank" rel="noreferrer">feathers-webpush</a>. Manages Web Push subscriptions and dispatches push notifications. Automatically cleans up expired subscriptions after each notification.</p><h2 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h2><h3 id="storage-1" tabindex="-1"><a href="./services/storage.html">storage</a> <a class="header-anchor" href="#storage-1" aria-label="Permalink to &quot;[storage](./services/storage.md)&quot;">​</a></h3><p>Powered by <a href="https://github.com/kalisio/feathers-s3" target="_blank" rel="noreferrer">feathers-s3</a>. Provides S3-backed object storage for blobs and resource attachments. Available as a global and contextual service.</p><h2 id="import-export" tabindex="-1">Import-Export <a class="header-anchor" href="#import-export" aria-label="Permalink to &quot;Import-Export&quot;">​</a></h2><h3 id="import-export-1" tabindex="-1"><a href="./services/import-export.html">import-export</a> <a class="header-anchor" href="#import-export-1" aria-label="Permalink to &quot;[import-export](./services/import-export.md)&quot;">​</a></h3><p>Powered by <a href="https://github.com/kalisio/feathers-import-export" target="_blank" rel="noreferrer">feathers-import-export</a>. Enables bulk data import and export via S3. Only <code>create</code> is allowed from the client side.</p><h2 id="databases" tabindex="-1">Databases <a class="header-anchor" href="#databases" aria-label="Permalink to &quot;Databases&quot;">​</a></h2><h3 id="databases-1" tabindex="-1"><a href="./services/databases.html">databases</a> <a class="header-anchor" href="#databases-1" aria-label="Permalink to &quot;[databases](./services/databases.md)&quot;">​</a></h3><p>Powered by <a href="https://github.com/feathersjs-ecosystem/feathers-mongodb-management" target="_blank" rel="noreferrer">feathers-mongodb-management</a>. Proxies MongoDB administrative operations (databases, collections, users). Server-side only.</p><h2 id="tags" tabindex="-1">Tags <a class="header-anchor" href="#tags" aria-label="Permalink to &quot;Tags&quot;">​</a></h2><h3 id="tags-1" tabindex="-1"><a href="./services/tags.html">tags</a> <a class="header-anchor" href="#tags-1" aria-label="Permalink to &quot;[tags](./services/tags.md)&quot;">​</a></h3><p>Manages contextual tags with fuzzy and diacritic-insensitive search. Enforces name uniqueness and propagates tag updates to all tagged resources via <code>reflectTagUpdate</code>.</p><h2 id="configurations" tabindex="-1">Configurations <a class="header-anchor" href="#configurations" aria-label="Permalink to &quot;Configurations&quot;">​</a></h2><h3 id="configurations-1" tabindex="-1"><a href="./services/configurations.html">configurations</a> <a class="header-anchor" href="#configurations-1" aria-label="Permalink to &quot;[configurations](./services/configurations.md)&quot;">​</a></h3><p>Stores named configuration objects (<code>{ name, value }</code>) for client-editable application settings. Available as a global and contextual service.</p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><h3 id="messages-1" tabindex="-1"><a href="./services/messages.html">messages</a> <a class="header-anchor" href="#messages-1" aria-label="Permalink to &quot;[messages](./services/messages.md)&quot;">​</a></h3><p>Manages contextual messages with full-text fuzzy search across title, body, and author. Timestamps are set and maintained automatically.</p><h2 id="local-settings" tabindex="-1">Local settings <a class="header-anchor" href="#local-settings" aria-label="Permalink to &quot;Local settings&quot;">​</a></h2><h3 id="local-settings-1" tabindex="-1"><a href="./services/local-settings.html">local-settings</a> <a class="header-anchor" href="#local-settings-1" aria-label="Permalink to &quot;[local-settings](./services/local-settings.md)&quot;">​</a></h3><p>Client-side service that bridges Feathers service interface with <code>localStorage</code> and the <a href="./application.html#store">global store</a>. Must be instantiated at application level.</p>',37)])])}const b=e(o,[["render",i]]);export{m as __pageData,b as default};
